1	import crypto from 'crypto';
2	import {
3	  IGeneratedTest,
4	  IQuestion,
5	  IAIFeedback,
6	  IContentForAI,
7	  IUserAnswer,
8	  IMistake,
9	  TestGenerationProfile
10	} from '../types';
11	import {
12	  parseAndValidateEntQuestions,
13	  parseAndValidateRegularQuestions,
14	  summarizeUserAnswer
15	} from '../utils/entQuestion.util';
16	import { extractFirstJsonObject } from '../utils/jsonExtract.util';
17	
18	function pickQuestionsArray(parsed: Record<string, unknown>): unknown[] | null {
19	  const q = parsed.questions;
20	  if (Array.isArray(q)) return q;
21	  const inner = parsed.data;
22	  if (inner && typeof inner === 'object' && !Array.isArray(inner)) {
23	    const dq = (inner as Record<string, unknown>).questions;
24	    if (Array.isArray(dq)) return dq;
25	  }
26	  return null;
27	}
