29	/**
30	 * AI SERVICE (MOCK)
31	 * Сервис для работы с AI (сейчас mock, готов к интеграции с OpenAI/LLM)
32	 * 
33	 * Текущая реализация:
34	 * - Генерирует mock вопросы на основе контента
35	 * - Анализирует ответы и создает обратную связь
36	 * 
37	 * Для production:
38	 * 1. Заменить mock логику на вызовы OpenAI API
39	 * 2. Использовать промпты для генерации качественных вопросов
40	 * 3. Добавить обработку rate limits и ошибок API
41	 * 4. Кешировать результаты где возможно
42	 */
43	
44	class AIService {
45	  /**
46	   * Генерация теста на основе контента
47	   * 
48	   * @param content - текстовый контент для генерации вопросов
49	   * @param metadata - метаданные о контенте (книга, глава и т.д.)
50	   * @param previousQuestions - хеши ранее сгенерированных вопросов для избежания повторений
51	   * @returns Сгенерированный тест с 10 вопросами
52	   * 
53	   * TODO: Интегрировать с OpenAI API
54	   * Пример промпта:
55	   * "Generate 10 multiple-choice questions based on the following text.
56	   *  Each question should have 4 options with only one correct answer.
57	   *  Avoid these previously used questions: [previousQuestions]
58	   *  Format: JSON with questionText, options[], correctOption, explanation"
59	   */
60	  async generateTest(
61	    content: IContentForAI,
62	    _previousQuestions: string[] = [],
63	    testProfile: TestGenerationProfile = 'ent',
64	    options?: { questionCount?: number }
65	  ): Promise<IGeneratedTest> {
66	    const apiKey = process.env.OPENAI_API_KEY;
67	    if (!apiKey) {
68	      throw new Error('OPENAI_API_KEY is not defined. Set it to enable real test generation.');
69	    }
70	
71	    const profile: TestGenerationProfile = testProfile === 'regular' ? 'regular' : 'ent';
72	    const qc = options?.questionCount;
73	    if (profile === 'regular' && qc != null && (qc < 1 || qc > 50)) {
74	      throw new Error('Обычный тест: укажите от 1 до 50 вопросов.');
75	    }
76	    if (profile === 'ent' && qc != null) {
77	      if (qc < 10 || qc > 120 || qc % 10 !== 0) {
78	        throw new Error('Формат ЕНТ: от 10 до 120 вопросов, кратно 10.');
79	      }
80	      if (qc > 10) {
81	        return this.generateEntBatchedTest(content, _previousQuestions, qc);
82	      }
83	    }
84	
85	    const expectedN =
86	      profile === 'regular' ? Math.min(50, Math.max(1, qc ?? 10)) : 10;
87	
88	    const sourceContentHash = this.hashContent(
89	      JSON.stringify({ v: 4, profile, n: expectedN, text: content.text })
90	    );
91	
92	    const topicsList = content.metadata.topics?.length
93	      ? `- relatedContent.topicTitle — точное название темы из списка: [${content.metadata.topics.join(', ')}]. Если вопрос не привязан к конкретной теме, опусти topicTitle.`
94	      : '';
95	
96	    const languageRule = content.metadata.contentLanguage?.trim()
97	      ? `- Язык полей questionText, всех вариантов/текстов заданий, aiExplanation и topicTitle: ${content.metadata.contentLanguage.trim()}. Не смешивай с другим языком.`
98	      : '- Язык вопросов, вариантов ответов и пояснений должен совпадать с языком приведённого учебного текста (например текст на казахском — весь вывод на казахском; на русском — на русском; на английском — на английском).';
99	
100	    const topicFocusHint = content.metadata.topicFocus?.trim()
101	      ? profile === 'regular'
102	        ? `- ВАЖНО: Все ${expectedN} вопросов должны быть сфокусированы на теме «${content.metadata.topicFocus.trim()}». Если в контенте недостаточно материала именно по этой теме, генерируй максимально близкие по смыслу вопросы.`
103	        : `- ВАЖНО: Все 10 вопросов должны быть сфокусированы на теме «${content.metadata.topicFocus.trim()}». Если в контенте недостаточно материала именно по этой теме, генерируй максимально близкие по смыслу вопросы.`
104	      : '';
105	
106	    const regularN = expectedN;
107	    const regularSpec = [
108	      `Сгенерируй ровно ${regularN} вопросов по учебному материалу — обычный тест (классический формат, не смешанный ЕНТ).`,
109	      'Все задания одного типа: один верный ответ из четырёх вариантов.',
110	      `Формат ответа: один JSON-объект вида {"questions":[ ... ровно ${regularN} элементов ... ]} без Markdown.`,
111	      '',
112	      'Каждый элемент массива questions:',
113	      '- questionType: всегда строка "single_choice"',
114	      '- questionText: формулировка задания',
115	      '- options: ровно 4 строки — варианты ответа',
116	      '- correctOption: одна строка, дословно совпадающая с одним из options',
117	      '- aiExplanation: кратко 1–2 предложения',
118	      '- relatedContent: { "pages": [числа], "topicTitle"?: "..." } — pages обязателен (можно приблизительно).',
119	      topicsList,
120	      '- Если в контенте есть формулы LaTeX ($...$ или $$...$$), сохраняй их в текстах.',
121	      _previousQuestions.length > 0 ? `- Избегай повторения смысла этих вопросов: ${_previousQuestions.join(' | ')}` : '',
122	      '',
123	      `КРИТИЧНО: массив questions ОБЯЗАТЕЛЬНО ровно из ${regularN} элементов. Не ${regularN - 1}, не ${
124	        regularN + 1
125	      } — ровно ${regularN}.`
126	    ].join('\n');
127	
128	    const entSpec = [
129	      'Ты — эксперт по подготовке к ЕНТ (Казахстан). Сгенерируй ровно 10 вопросов в форматах, приближённых к реальному ЕНТ.',
130	      'Формат ответа: один JSON-объект вида {"questions":[ ... ровно 10 элементов ... ]} без Markdown, без пояснений до или после JSON.',
131	      '',
132	      'РАСПРЕДЕЛЕНИЕ ПО ТИПАМ (строго по одному на каждый номер):',
133	      '1–3: single_choice — один верный ответ, 4–5 вариантов в поле options, correctOption — точная строка из options.',
134	      '4–5: multiple_choice — несколько верных, в options от 4 до 10 строк (по возможности не меньше 5), correctOptions — массив из 2–4 строк (каждая должна входить в options).',
135	      '6–7: matching_single — сопоставление «один к одному». matchingLeft и matchingRight: по 3–5 элементов { "id": "L1", "text": "..." }; id уникальны внутри колонки. correctMatching: объект { "L1": "R2", ... } — каждый ключ из matchingLeft, значение — id из matchingRight; каждый правый id используется ровно один раз.',
136	      '8: matching_multiple — один ко многим: matchingLeft 2–5 элементов, matchingRight 3–10. correctMatching: { "L1": ["R1","R3"], ... } — непустые массивы id из matchingRight.',
137	      '9: short_answer — короткий ответ (число или слово). Поля: acceptableAnswers: массив из 1–5 эквивалентных форм (например "4", "четыре"). Без options.',
138	      '10: text_input — развёрнутый ввод. Обязательно задай проверку: acceptableKeywords (3–6 ключевых слов/фраз) ИЛИ acceptableAnswers (2–4 эталонных фрагмента) ИЛИ referenceAnswer (краткий образцовый ответ). Без options.',
139	      '',
140	      'Общие поля каждого объекта вопроса:',
141	      '- questionType: одно из: single_choice | multiple_choice | matching_single | matching_multiple | short_answer | text_input',
142	      '- questionText: формулировка задания',
143	      '- aiExplanation: 1–2 предложения пояснения после ответа (обязательно у каждого вопроса; не пустая строка). Допустимо поле explanation как синоним — сервер примет, но лучше aiExplanation.',
144	      '- relatedContent: { "pages": [числа], "topicTitle"?: "..." } — pages обязателен (можно приблизительно).',
145	      topicsList,
146	      '- Если в контенте есть формулы LaTeX ($...$ или $$...$$), сохраняй их в текстах.',
147	      _previousQuestions.length > 0 ? `- Избегай повторения смысла этих вопросов: ${_previousQuestions.join(' | ')}` : '',
148	      '',
149	      'КРИТИЧНО: массив questions ОБЯЗАТЕЛЬНО ровно из 10 элементов (индексы 0–9). Не 9, не 11 — только 10.'
150	    ].join('\n');
151	
152	    const specBody = profile === 'regular' ? regularSpec : entSpec;
153	    const prompt = [
154	      specBody,
155	      '',
156	      'Требования:',
157	      languageRule,
158	      topicFocusHint,
159	      '',
160	      'Контент для генерации:',
161	      content.text
162	    ]
163	      .filter(Boolean)
164	      .join('\n');
165	
166	    const contentPreview = content.text.length > 800
167	      ? `${content.text.slice(0, 800)}...`
168	      : content.text;
169	
170	    const systemContent =
171	      profile === 'regular'
172	        ? `Ты составляешь обычные тесты по учебнику: ровно ${expectedN} вопросов с четырьмя вариантами и одним верным ответом. Ответь одним JSON-объектом с ключом questions; без Markdown и без текста вне JSON.`
173	        : 'Ты генерируешь проверочные задания по учебному контенту в форматах, приближённых к ЕНТ (Казахстан): один и несколько верных ответов, сопоставление, короткий и развёрнутый ответ. Ответь одним JSON-объектом с ключом questions — массив из ровно 10 элементов; без Markdown и без текста вне JSON.';
174	
175	    const max_tokens =
176	      profile === 'regular' ? Math.min(12000, 1500 + expectedN * 500) : 16000;
177	
178	    console.log('🤖 [AI] generateTest:start', {
179	      model: 'gpt-4o-mini',
180	      profile,
181	      subject: content.metadata.subjectTitle,
182	      book: content.metadata.bookTitle,
183	      chapter: content.metadata.chapterTitle ?? 'Вся книга',
184	      topicsCount: content.metadata.topics.length,
185	      contentChars: content.text.length,
186	      contentHash: sourceContentHash,
187	      previousQuestionsCount: _previousQuestions.length
188	    });
189	    console.log('🤖 [AI] prompt:begin');
190	    console.log(prompt);
191	    console.log('🤖 [AI] prompt:end');
192	    console.log('🤖 [AI] contentPreview', contentPreview);
193	
194	    type ChatMsg = { role: 'system' | 'user' | 'assistant'; content: string };
195	    const chatMessages: ChatMsg[] = [
196	      { role: 'system', content: systemContent },
197	      { role: 'user', content: prompt }
198	    ];
199	
200	    let questions: IQuestion[] | undefined;
201	
202	    for (let attempt = 0; attempt < 2; attempt++) {
203	      const raw = await this.openAiJsonCompletion(apiKey, chatMessages, max_tokens, attempt === 0 ? 0.45 : 0.2);
204	      console.log('🤖 [AI] response:raw', raw);
205	
206	      const jsonStr = extractFirstJsonObject(raw);
207	      if (!jsonStr) {
208	        console.error('🤖 [AI] response:parse-error', { attempt: attempt + 1, rawPreview: raw.slice(0, 500) });
209	        if (attempt === 1) {
210	          throw new Error('OpenAI response does not contain a parseable JSON object.');
211	        }
212	        chatMessages.push(
213	          { role: 'assistant', content: raw },
214	          {
215	            role: 'user',
216	            content: `Ответ не удалось разобрать как JSON-объект. Верни один JSON-объект с ключом questions (массив из ровно ${expectedN} элементов), без текста до или после.`
217	          }
218	        );
219	        continue;
220	      }
221	
222	      let parsed: Record<string, unknown>;
223	      try {
224	        parsed = JSON.parse(jsonStr) as Record<string, unknown>;
225	      } catch (e) {
226	        console.error('🤖 [AI] response:json-parse', { attempt: attempt + 1, error: e });
227	        if (attempt === 1) {
228	          throw new Error('OpenAI response is not valid JSON.');
229	        }
230	        chatMessages.push(
231	          { role: 'assistant', content: raw },
232	          { role: 'user', content: 'JSON синтаксически неверен. Исправь и верни один корректный JSON-объект с ключом questions.' }
233	        );
234	        continue;
235	      }
236	
237	      const rawQuestions = pickQuestionsArray(parsed);
238	      if (!rawQuestions) {
239	        console.error('🤖 [AI] response:no-questions-array', {
240	          attempt: attempt + 1,
241	          keys: Object.keys(parsed)
242	        });
243	        if (attempt === 1) {
244	          throw new Error('OpenAI JSON must contain root key "questions" (array).');
245	        }
246	        chatMessages.push(
247	          { role: 'assistant', content: raw },
248	          {
249	            role: 'user',
250	            content: `В JSON нет массива questions в корне. Верни объект вида {"questions":[ ... ]} с ровно ${expectedN} вопросами.`
251	          }
252	        );
253	        continue;
254	      }
255	
256	      const n = rawQuestions.length;
257	      if (n !== expectedN) {
258	        console.warn('🤖 [AI] questions:wrong-length', { attempt: attempt + 1, profile, count: n });
259	        if (attempt === 1) {
260	          throw new Error(
261	            profile === 'regular'
262	              ? `Обычный тест: ожидалось ровно ${expectedN} вопросов, получено ${n}.`
263	              : `OpenAI response: ожидалось ровно 10 вопросов, получено ${n}. Проверьте промпт и повторите запрос.`
264	          );
265	        }
266	        const fixMsg =
267	          profile === 'regular'
268	            ? `В твоём JSON массив questions содержит ${n} элементов, а нужно РОВНО ${expectedN}. Верни полный JSON-объект: ${expectedN} вопросов, каждый single_choice с ровно 4 вариантами.`
269	            : `В твоём JSON массив questions содержит ${n} элементов, а нужно РОВНО 10 по схеме ЕНТ (номера 1–10 и типы как в задании выше). Верни полный JSON-объект с ключом questions длиной 10 — допиши недостающие вопросы или пересобери массив целиком.`;
270	        chatMessages.push({ role: 'assistant', content: raw }, { role: 'user', content: fixMsg });
271	        continue;
272	      }
273	
274	      try {
275	        questions =
276	          profile === 'regular'
277	            ? parseAndValidateRegularQuestions(rawQuestions, expectedN)
278	            : parseAndValidateEntQuestions(rawQuestions);
279	        break;
280	      } catch (e) {
281	        console.error('🤖 [AI] response:invalid-questions', {
282	          attempt: attempt + 1,
283	          profile,
284	          error: e,
285	          questionsCount: n
286	        });
287	        if (attempt === 1) {
288	          throw e instanceof Error ? e : new Error('Invalid questions from model.');
289	        }
290	        chatMessages.push(
291	          { role: 'assistant', content: raw },
292	          {
293	            role: 'user',
294	            content: `Массив из ${expectedN} элементов есть, но проверка не прошла: ${
295	              e instanceof Error ? e.message : String(e)
296	            }. Исправь структуру каждого вопроса и верни полный JSON с questions (ровно ${expectedN} элементов).`
297	          }
298	        );
299	      }
300	    }
301	
302	    if (!questions) {
303	      throw new Error('Не удалось сгенерировать вопросы после повторной попытки.');
304	    }
305	
306	    for (const question of questions) {
307	      if (!question.relatedContent?.pages?.length) {
308	        question.relatedContent = { ...question.relatedContent, pages: [1] };
309	      }
310	    }
311	
312	    console.log('🤖 [AI] generateTest:done', { questionsCount: questions.length });
313	    return { questions, sourceContentHash };
314	  }
315	
316	  /**
317	   * Несколько подряд серий по 10 вопросов (ЕНТ) без дублирования смысла между сериями.
318	   */
319	  private async generateEntBatchedTest(
320	    content: IContentForAI,
321	    _previousQuestions: string[],
322	    total: number
323	  ): Promise<IGeneratedTest> {
324	    const batches = total / 10;
325	    const all: IQuestion[] = [];
326	    let prev = [..._previousQuestions];
327	    for (let b = 0; b < batches; b++) {
328	      const paddedContent: IContentForAI =
329	        batches > 1 && b > 0
330	          ? {
331	              ...content,
332	              text:
333	                `${content.text}\n\n(Продолжение: серия ${b + 1} из ${batches}, по 10 вопросов в формате ЕНТ. Не повторяй смыслы вопросов из предыдущих серий; опирайся на другие разделы и факты учебного материала.)`
334	            }
335	          : content;
336	      const part = await this.generateTest(paddedContent, prev, 'ent');
337	      all.push(...part.questions);
338	      prev = [
339	        ...prev,
340	        ...part.questions.map((q) => Buffer.from(q.questionText).toString('base64'))
341	      ];
342	    }
343	    for (const question of all) {
344	      if (!question.relatedContent?.pages?.length) {
345	        question.relatedContent = { ...question.relatedContent, pages: [1] };
346	      }
347	    }
348	    const sourceContentHash = this.hashContent(
349	      JSON.stringify({ v: 3, profile: 'ent', n: total, text: content.text })
350	    );
351	    return { questions: all, sourceContentHash };
352	  }
