354	  /**
355	   * Анализ ответов пользователя и генерация обратной связи
356	   * 
357	   * @param test - тест с правильными ответами
358	   * @param userAnswers - ответы пользователя
359	   * @param content - контент для ссылок на материал
360	   * @returns AI обратная связь с анализом ошибок
361	   * 
362	   * TODO: Интегрировать с OpenAI для персонализированной обратной связи
363	   * Пример промпта:
364	   * "Analyze the student's answers and provide personalized feedback.
365	   *  Identify weak areas and suggest specific sections to review.
366	   *  Be encouraging but point out areas for improvement."
367	   */
368	  async analyzeAnswers(
369	    correctAnswers: Array<{
370	      question: string;
371	      correctSummary: string;
372	      explanation: string;
373	      relatedContent?: { pages?: number[]; topicTitle?: string };
374	    }>,
375	    userAnswers: IUserAnswer[],
376	    contentMetadata: IContentForAI['metadata']
377	  ): Promise<IAIFeedback> {
378	    // Симуляция задержки API
379	    await this.delay(800);
380	
381	    // Подсчитываем правильные ответы
382	    const correctCount = userAnswers.filter(a => a.isCorrect).length;
383	    const totalCount = userAnswers.length;
384	    const scorePercent = Math.round((correctCount / totalCount) * 100);
385	
386	    // Анализируем ошибки
387	    const mistakes: IMistake[] = [];
388	
389	    for (let i = 0; i < userAnswers.length; i++) {
390	      const userAnswer = userAnswers[i];
391	      const correctAnswer = correctAnswers[i];
392	
393	      if (!userAnswer.isCorrect) {
394	        const mistake: IMistake = {
395	          question: userAnswer.question,
396	          explanation: `Ваш ответ: ${summarizeUserAnswer(userAnswer.selectedOption)}. Ожидается: ${correctAnswer.correctSummary}. ${correctAnswer.explanation}`
397	        };
398	        if (contentMetadata.bookTitle?.trim()) {
399	          const rcPages = correctAnswer.relatedContent?.pages;
400	          const pages = rcPages && rcPages.length > 0 ? rcPages : [1];
401	          mistake.whereToRead = {
402	            bookTitle: contentMetadata.bookTitle,
403	            chapterTitle: contentMetadata.chapterTitle || 'Вся книга',
404	            pages,
405	            topicTitle: correctAnswer.relatedContent?.topicTitle
406	          };
407	        }
408	        mistakes.push(mistake);
409	      }
410	    }
411	
412	    // Генерируем общий вывод
413	    let summary = '';
414	    
415	    if (scorePercent >= 90) {
416	      summary = `Отличная работа! Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Вы демонстрируете отличное понимание материала по теме "${contentMetadata.bookTitle}".`;
417	    } else if (scorePercent >= 70) {
418	      summary = `Хороший результат! Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Рекомендуем повторить материал по темам, где были допущены ошибки.`;
419	    } else if (scorePercent >= 50) {
420	      summary = `Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Необходимо более внимательно изучить материал. Обратите особое внимание на разделы, указанные в ошибках ниже.`;
421	    } else {
422	      summary = `Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Рекомендуем полностью перечитать главу "${contentMetadata.chapterTitle || contentMetadata.bookTitle}" и попробовать пройти тест снова.`;
423	    }
424	
425	    if (mistakes.length > 0) {
426	      summary += ` Всего допущено ошибок: ${mistakes.length}. Подробный разбор ошибок представлен ниже.`;
427	    }
428	
429	    return {
430	      summary,
431	      mistakes
432	    };
433	  }
