452	  private async openAiJsonCompletion(
453	    apiKey: string,
454	    messages: Array<{ role: 'system' | 'user' | 'assistant'; content: string }>,
455	    max_tokens: number,
456	    temperature: number
457	  ): Promise<string> {
458	    const response = await fetch('https://api.openai.com/v1/chat/completions', {
459	      method: 'POST',
460	      headers: {
461	        'Content-Type': 'application/json',
462	        Authorization: `Bearer ${apiKey}`
463	      },
464	      body: JSON.stringify({
465	        model: 'gpt-4o-mini',
466	        temperature,
467	        max_tokens,
468	        response_format: { type: 'json_object' },
469	        messages
470	      })
471	    });
472	
473	    if (!response.ok) {
474	      const errorText = await response.text();
475	      console.error('🤖 [AI] response:error', { status: response.status, errorText });
476	      throw new Error(`OpenAI API error: ${response.status} ${errorText}`);
477	    }
478	
479	    const data = (await response.json()) as {
480	      choices?: Array<{ message?: { content?: string } }>;
481	    };
482	
483	    return data.choices?.[0]?.message?.content ?? '';
484	  }
