174	  /** Проверить ответы, вернуть userAnswers и счёт */
175	  private checkAnswers(test: any, answers: ISubmitTestDTO['answers']) {
176	    if (answers.length !== test.questions.length) {
177	      throw AppError.badRequest(`Expected ${test.questions.length} answers, received ${answers.length}`);
178	    }
179	
180	    const userAnswers: IUserAnswer[] = [];
181	    let correctCount = 0;
182	
183	    for (const question of test.questions) {
184	      const ua = answers.find((a) => a.questionText === question.questionText);
185	      if (!ua) throw AppError.badRequest(`Missing answer for question: "${question.questionText}"`);
186	
187	      const isCorrect = gradeAnswer(question as IQuestion, ua.selectedOption);
188	      if (isCorrect) correctCount++;
189	      userAnswers.push({ question: question.questionText, selectedOption: ua.selectedOption, isCorrect });
190	    }
191	
192	    const totalQuestions = test.questions.length;
193	    return {
194	      userAnswers,
195	      result: { totalQuestions, correctAnswers: correctCount, scorePercent: Math.round((correctCount / totalQuestions) * 100) }
196	    };
