508	
509	    const test = await Test.findById(session.testId);
510	    if (!test) throw AppError.notFound('Test not found');
511	    if (session.answers.length !== test.questions.length) {
512	      throw AppError.badRequest('Solo session is not complete yet');
513	    }
514	
515	    const finalScore = session.answers.reduce((sum, item) => sum + item.questionScore, 0);
516	    const correctCount = session.answers.filter((item) => item.isCorrect).length;
