1	import { Subject } from '../models';
2	import { aiService } from './ai.service';
3	import {
4	  IQuestion,
5	  IUserAnswer,
6	  ITestResult,
7	  IAIFeedback
8	} from '../types';
9	import { formatExpectedAnswer, getQuestionType } from '../utils/entQuestion.util';
10	import { ROADMAP_MASTERY_THRESHOLD_PERCENT } from '../roadmap/roadmap.rules';
11	
12	/** Тема, которую стоит повторить (есть ошибки в тесте). */
13	export interface ITopicToReview {
14	  topicId: string;
15	  topicTitle: string;
16	  totalCount: number;
17	  wrongCount: number;
18	  scorePercent: number;
19	}
20	
21	/** Минимальный набор полей теста, нужный для разбора. Совместим с Test-документом и lean. */
22	interface TestLike {
23	  _id?: unknown;
24	  subjectId: unknown;
25	  bookId: unknown;
26	  chapterId?: unknown;
27	  questions: IQuestion[];
28	}
29	
30	interface ResolvedContext {
31	  subjectTitle: string;
32	  bookTitle: string;
33	  chapterTitle?: string;
34	  chapterTopicTitles: string[];
35	  /** topicId(string) -> title темы (резолв из Subject.books[].chapters[].topics[]) */
36	  topicTitleById: Map<string, string>;
37	}
