233	UserSchema.methods.getAllQuestionHashes = function(subjectId: string, bookId: string): string[] {
234	  return this.testHistory
235	    .filter((test: ITestHistory) => 
236	      test.subjectId.toString() === subjectId && 
237	      test.bookId.toString() === bookId
238	    )
239	    .flatMap((test: ITestHistory) => test.generatedQuestionsHash);
240	};
